// ============================================================
// Sales Order — "Get Items From > Tender" Custom Script
// Doctype: Sales Order | Type: Client Script
// Filter: status = Qualified AND qualified_status = Purchase Order
// Columns: Tender ID, Consignee Name, Vanue, Status, Qualified Status
// ============================================================

frappe.ui.form.on('Sales Order', {

    refresh: function (frm) {
        frm.add_custom_button(__('Tender'), function () {
            open_tender_dialog(frm);
        }, __('Get Items From'));
    }

});

function open_tender_dialog(frm) {

    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Tender',
            filters: [
                ['status', '=', 'Qualified'],
                ['qualified_status', '=', 'Purchase Order']
            ],
            fields: ['name', 'tender_id', 'consignee_name', 'vanue', 'status', 'qualified_status'],
            limit: 100
        },
        callback: function (r) {
            let tenders = r.message || [];

            let dialog = new frappe.ui.Dialog({
                title: __('Select Tender'),
                size: 'extra-large',
                fields: [
                    {
                        fieldname: 'tender_list_html',
                        fieldtype: 'HTML',
                        options: build_table_html(tenders)
                    }
                ],
                primary_action_label: __('Get Items'),
                primary_action: function () {
                    let selected_name = dialog.selected_tender;

                    if (!selected_name) {
                        frappe.msgprint(__('Please select a Tender from the list.'));
                        return;
                    }

                    frappe.db.get_doc('Tender', selected_name).then(function (tender) {

                        // ── 1. consignee_name → Customer
                        if (tender.consignee_name) {
                            frm.set_value('customer', tender.consignee_name);
                        }

                        // ── 2. Tender name → custom_tender_id
                        frm.set_value('custom_tender_id', tender.name);

                        // ── 3. Sirf FIRST BOQ item levo
                        let boq = tender.boq_items || tender.items || [];

                        if (!boq.length) {
                            frappe.msgprint(__('No BOQ items found in this Tender.'));
                            return;
                        }

                        let first = boq[0];

                        // Blank rows clean karo
                        (frm.doc.items || []).slice().forEach(function (row) {
                            if (!row.item_code) {
                                frappe.model.clear_doc(row.doctype, row.name);
                            }
                        });

                        // // First item add karo
                        // let child       = frm.add_child('items');
                        // child.item_code = first.item || first.item_code || '';
                        // child.qty       = first.qty  || 1;
                        // child.rate      = tender.final_total || 0;
                        
                        let child = frm.add_child('items');

                        // item_code set with trigger
                        frappe.model.set_value(
                            child.doctype,
                            child.name,
                            'item_code',
                            first.item || first.item_code || ''
                        );
                        
                        // qty
                        frappe.model.set_value(
                            child.doctype,
                            child.name,
                            'qty',
                            first.qty || 1
                        );
                        
                        // force trigger (important)
                        frm.script_manager.trigger("item_code", child.doctype, child.name);
                        
                        // ⬇️ RATE LAST ma set karo (THIS IS FIX)
                        setTimeout(() => {
                            frappe.model.set_value(
                                child.doctype,
                                child.name,
                                'rate',
                                tender.final_total || 0
                            );
                        }, 200);

                        frm.refresh_field('items');
                        frm.refresh_field('customer');
                        frm.refresh_field('custom_tender_id');

                        dialog.hide();

                        frappe.show_alert({
                            message: __('Tender {0} loaded!', [tender.tender_id || selected_name]),
                            indicator: 'green'
                        });

                    }).catch(function () {
                        frappe.msgprint(__('Failed to load Tender. Please try again.'));
                    });
                }
            });

            dialog.show();
            dialog.selected_tender = null;

            dialog.$wrapper.find('.tender-row').on('click', function () {
                let $row = $(this);
                let name = $row.data('name');

                dialog.$wrapper.find('.tender-row')
                    .removeClass('selected-row')
                    .find('.tender-check').prop('checked', false);

                $row.addClass('selected-row')
                    .find('.tender-check').prop('checked', true);

                dialog.selected_tender = name;
            });
        }
    });
}

function build_table_html(tenders) {

    let styles = `
        <style>
            .tender-table {
                width: 100%;
                border-collapse: collapse;
                font-size: 13px;
            }
            .tender-table th {
                background: var(--control-bg);
                padding: 10px 14px;
                text-align: left;
                border-bottom: 2px solid var(--border-color);
                font-weight: 600;
                color: var(--text-muted);
                white-space: nowrap;
            }
            .tender-table td {
                padding: 10px 14px;
                border-bottom: 1px solid var(--border-color);
                color: var(--text-color);
                vertical-align: middle;
            }
            .tender-row { cursor: pointer; transition: background 0.12s; }
            .tender-row:hover { background: var(--control-bg-on-gray); }
            .tender-row.selected-row { background: #dbeafe; }
            .badge-qualified {
                background: #d1fae5; color: #065f46;
                padding: 3px 10px; border-radius: 12px;
                font-size: 11px; font-weight: 600;
                white-space: nowrap;
            }
            .badge-po {
                background: #dbeafe; color: #1e40af;
                padding: 3px 10px; border-radius: 12px;
                font-size: 11px; font-weight: 600;
                white-space: nowrap;
            }
            .no-data {
                text-align: center;
                padding: 32px;
                color: var(--text-muted);
                font-size: 13px;
            }
        </style>
    `;

    let rows = '';

    if (!tenders.length) {
        rows = `<tr><td colspan="6" class="no-data">
            No Tenders found with Status = Qualified &amp; Qualified Status = Purchase Order
        </td></tr>`;
    } else {
        tenders.forEach(function (t) {
            rows += `
                <tr class="tender-row" data-name="${t.name}">
                    <td style="width:40px; text-align:center">
                        <input class="tender-check" type="checkbox"
                            style="cursor:pointer; width:15px; height:15px; pointer-events:none">
                    </td>
                    <td><b>${t.tender_id || t.tender_id}</b></td>
                    <td>${t.consignee_name || '—'}</td>
                    <td>${t.vanue || '—'}</td>
                    <td><span class="badge-qualified">${t.status || 'Qualified'}</span></td>
                    <td><span class="badge-po">${t.qualified_status || 'Purchase Order'}</span></td>
                </tr>
            `;
        });
    }

    return `
        ${styles}
        <table class="tender-table">
            <thead>
                <tr>
                    <th></th>
                    <th>Tender ID</th>
                    <th>Consignee Name</th>
                    <th>Vanue</th>
